                        </div>
                        <span className="font-bold">{step.title}</span>
                    </button>
                 ))}
             </div>

             {/* Detail Card */}
             <div className="col-span-2 md:col-span-2">
                 {steps.map((step) => (
                     activeStep === step.id && (
                         <div key={step.id} className="glass-panel p-8 md:p-12 rounded-[2.5rem] flex flex-col md:flex-row gap-8 items-center reveal-up">
                             <div className="flex-1 space-y-4">
                                 <div className="inline-block px-4 py-1 rounded-full bg-primary/20 text-deep-green text-xs font-bold uppercase tracking-widest mb-2">
                                     Stap {step.id}: {step.tag}
                                 </div>
                                 <h3 className="text-3xl font-serif text-deep-green">{step.title}</h3>
                                 <h4 className="text-xl text-primary font-medium">{step.subtitle}</h4>
                                 <p className="text-deep-green/70 leading-relaxed text-lg">{step.description}</p>
                             </div>
                             <div className="flex-1 w-full flex justify-center">
                                 <div className="w-full max-w-sm aspect-square bg-gradient-to-br from-deep-green to-black rounded-2xl flex items-center justify-center relative overflow-hidden shadow-2xl">
                                     <step.icon size={120} className="text-primary opacity-20" />
                                     <div className="absolute inset-0 bg-primary/10 backdrop-blur-[2px]"></div>
                                     <div className="absolute bottom-6 right-6">
                                         <button className="bg-white/10 hover:bg-white/20 backdrop-blur-md text-white p-4 rounded-full border border-white/20 transition-all">
                                             <ArrowRight />
                                         </button>
                                     </div>
                                 </div>
                             </div>
                         </div>
                     )
                 ))}
             </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Roadmap;

